<!DOCTYPE html>
<html lang="it">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>AI·CYBER // NEGOZIO DI PROGRAMMAZIONE</title>
  <!-- Font e icone -->
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Inter:opsz,wght@14..32,300;500;700&display=swap" rel="stylesheet">
  <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/css/all.min.css">
  <style>
    /* RESET & BASE */
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    body {
      background: #0a0f1e;
      color: #e0f0ff;
      font-family: 'Inter', sans-serif;
      line-height: 1.5;
      scroll-behavior: smooth;
      overflow-x: hidden;
    }

    /* CYBERPUNK TIPOGRAFIA */
    h1, h2, h3, .cyber-title {
      font-family: 'Orbitron', sans-serif;
      letter-spacing: 0.1em;
      text-transform: uppercase;
      text-shadow: 0 0 10px #00f0ff, 0 0 30px #00b0ff;
    }

    .neon-glow {
      text-shadow: 0 0 5px #00f0ff, 0 0 20px #00b0ff, 0 0 40px #0050ff;
    }

    /* LAYOUT */
    .container {
      max-width: 1200px;
      margin: 0 auto;
      padding: 0 24px;
    }

    /* NAV */
    nav {
      position: fixed;
      top: 0;
      width: 100%;
      background: rgba(10, 15, 30, 0.85);
      backdrop-filter: blur(8px);
      border-bottom: 2px solid #00f0ff;
      box-shadow: 0 0 20px rgba(0, 240, 255, 0.3);
      z-index: 1000;
      padding: 0.8rem 0;
    }

    nav .container {
      display: flex;
      justify-content: space-between;
      align-items: center;
      flex-wrap: wrap;
    }

    .nav-brand {
      font-family: 'Orbitron', sans-serif;
      font-weight: 900;
      font-size: 1.8rem;
      color: #00f0ff;
      text-decoration: none;
      letter-spacing: 0.2em;
      text-shadow: 0 0 15px #00aaff;
    }

    .nav-brand span {
      color: #ff0077;
      text-shadow: 0 0 20px #ff0077;
    }

    .nav-links {
      display: flex;
      gap: 2rem;
      list-style: none;
    }

    .nav-links a {
      color: #c0d0ff;
      text-decoration: none;
      font-weight: 500;
      transition: 0.2s;
      padding: 0.3rem 0.5rem;
      border-radius: 4px;
    }

    .nav-links a:hover {
      color: #00f0ff;
      background: rgba(0, 240, 255, 0.1);
      box-shadow: 0 0 12px #00f0ff;
    }

    /* HERO */
    .hero {
      min-height: 100vh;
      display: flex;
      align-items: center;
      justify-content: center;
      background: radial-gradient(circle at 20% 30%, #0f1a30, #050810);
      border-bottom: 3px solid #ff0077;
      box-shadow: inset 0 -20px 40px rgba(255, 0, 119, 0.2);
      padding-top: 80px;
    }

    .hero-content {
      text-align: center;
      max-width: 800px;
    }

    .hero h1 {
      font-size: 3.5rem;
      margin-bottom: 1rem;
      color: #f0f8ff;
    }

    .hero .sub {
      font-size: 1.4rem;
      font-weight: 300;
      color: #b0c0ff;
      margin-bottom: 2rem;
      border-right: 2px solid #00f0ff;
      padding-right: 0.5rem;
      display: inline-block;
    }

    .hero .cta-button {
      background: transparent;
      border: 2px solid #ff0077;
      color: #ff0077;
      padding: 1rem 3rem;
      font-family: 'Orbitron', sans-serif;
      font-weight: 700;
      font-size: 1.3rem;
      text-transform: uppercase;
      letter-spacing: 0.2em;
      border-radius: 60px;
      transition: 0.3s;
      cursor: pointer;
      background: rgba(255, 0, 119, 0.05);
      box-shadow: 0 0 15px rgba(255, 0, 119, 0.3);
    }

    .hero .cta-button:hover {
      background: #ff0077;
      color: #0a0f1e;
      box-shadow: 0 0 40px #ff0077, 0 0 80px #ff0077;
      transform: scale(1.05);
    }

    /* SERVIZI */
    .services {
      background: #0d1225;
      padding: 5rem 0;
      border-top: 2px solid #00f0ff;
      border-bottom: 2px solid #00f0ff;
      box-shadow: 0 0 30px rgba(0, 240, 255, 0.2);
    }

    .services h2 {
      text-align: center;
      font-size: 2.8rem;
      margin-bottom: 3rem;
      color: #00f0ff;
    }

    .service-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
      gap: 2rem;
    }

    .service-card {
      background: #1a1f30;
      border: 1px solid #2a3a5a;
      border-radius: 20px;
      padding: 2rem 1.5rem;
      transition: 0.3s;
      box-shadow: 0 10px 20px rgba(0,0,0,0.6);
      text-align: center;
    }

    .service-card:hover {
      border-color: #00f0ff;
      box-shadow: 0 0 30px #00f0ff, 0 0 60px #0050ff;
      transform: translateY(-6px);
    }

    .service-card i {
      font-size: 3rem;
      color: #ff0077;
      margin-bottom: 1rem;
      text-shadow: 0 0 20px #ff0077;
    }

    .service-card h3 {
      font-size: 1.6rem;
      margin-bottom: 0.8rem;
      color: #e0f0ff;
    }

    .service-card p {
      color: #b0c0d0;
      font-weight: 300;
    }

    /* MODULO CONTATTI */
    .contact {
      background: #0a0f1e;
      padding: 5rem 0;
    }

    .contact h2 {
      text-align: center;
      font-size: 2.8rem;
      margin-bottom: 2rem;
      color: #ff0077;
      text-shadow: 0 0 20px #ff0077;
    }

    .contact-form {
      max-width: 700px;
      margin: 0 auto;
      background: #141a2b;
      padding: 2.5rem 2rem;
      border-radius: 30px;
      border: 1px solid #ff0077;
      box-shadow: 0 0 30px rgba(255, 0, 119, 0.2);
    }

    .contact-form input,
    .contact-form textarea {
      width: 100%;
      padding: 1rem 1.2rem;
      margin-bottom: 1.5rem;
      background: #1e2538;
      border: 1px solid #2a3a5a;
      border-radius: 40px;
      color: #e0f0ff;
      font-size: 1rem;
      transition: 0.2s;
      outline: none;
    }

    .contact-form input:focus,
    .contact-form textarea:focus {
      border-color: #00f0ff;
      box-shadow: 0 0 20px #00f0ff;
    }

    .contact-form textarea {
      height: 140px;
      resize: vertical;
      border-radius: 20px;
    }

    .contact-form button {
      background: transparent;
      border: 2px solid #00f0ff;
      color: #00f0ff;
      padding: 1rem 2.5rem;
      font-family: 'Orbitron', sans-serif;
      font-weight: 700;
      font-size: 1.2rem;
      text-transform: uppercase;
      letter-spacing: 0.2em;
      border-radius: 60px;
      transition: 0.3s;
      cursor: pointer;
      background: rgba(0, 240, 255, 0.05);
      width: 100%;
    }

    .contact-form button:hover {
      background: #00f0ff;
      color: #0a0f1e;
      box-shadow: 0 0 40px #00f0ff;
    }

    /* FOOTER */
    footer {
      text-align: center;
      padding: 2rem 0;
      border-top: 1px solid #2a3a5a;
      color: #7a8aaa;
      font-size: 0.9rem;
    }

    footer .cyber-title {
      font-size: 1rem;
      color: #00f0ff;
    }

    /* POPUP (JavaScript) */
    .popup-overlay {
      display: none;
      position: fixed;
      top: 0; left: 0; width: 100%; height: 100%;
      background: rgba(0, 0, 0, 0.8);
      backdrop-filter: blur(4px);
      z-index: 9999;
      justify-content: center;
      align-items: center;
      animation: fadeIn 0.3s ease;
    }

    .popup-overlay.active {
      display: flex;
    }

    .popup-box {
      background: #141a2b;
      border: 2px solid #00f0ff;
      border-radius: 30px;
      padding: 2.5rem 2rem;
      max-width: 450px;
      width: 90%;
      text-align: center;
      box-shadow: 0 0 60px #00f0ff;
      animation: popIn 0.3s ease;
    }

    .popup-box h3 {
      font-size: 2rem;
      color: #ff0077;
      margin-bottom: 1rem;
    }

    .popup-box p {
      color: #c0d0ff;
      margin-bottom: 1.5rem;
    }

    .popup-box .popup-close {
      background: transparent;
      border: 2px solid #ff0077;
      color: #ff0077;
      padding: 0.8rem 2rem;
      font-family: 'Orbitron', sans-serif;
      font-weight: 700;
      border-radius: 40px;
      cursor: pointer;
      transition: 0.2s;
      background: rgba(255, 0, 119, 0.1);
    }

    .popup-box .popup-close:hover {
      background: #ff0077;
      color: #0a0f1e;
      box-shadow: 0 0 30px #ff0077;
    }

    @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
    @keyframes popIn { from { transform: scale(0.8); opacity: 0; } to { transform: scale(1); opacity: 1; } }

    /* RESPONSIVE */
    @media (max-width: 700px) {
      nav .container {
        flex-direction: column;
        gap: 0.5rem;
      }
      .nav-links {
        gap: 1rem;
        flex-wrap: wrap;
        justify-content: center;
      }
      .hero h1 {
        font-size: 2.5rem;
      }
    }
  </style>
</head>
<body>
  <!-- NAV -->
  <nav>
    <div class="container">
      <a href="#" class="nav-brand">AI<span>//</span>CYBER</a>
      <ul class="nav-links">
        <li><a href="#hero">Home</a></li>
        <li><a href="#services">Servizi</a></li>
        <li><a href="#contact">Contatti</a></li>
      </ul>
    </div>
  </nav>

  <!-- HERO -->
  <section id="hero" class="hero">
    <div class="hero-content">
      <h1 class="neon-glow">⚡ AI PROGRAMMING</h1>
      <p class="sub">codice neurale · cybernetico · quantico</p>
      <button class="cta-button" id="heroPopupBtn">ACCEDI AL FUTURO</button>
    </div>
  </section>

